 35→const toCount = (value: unknown): number | null => {
 36→  const parsed = Number(value);
 37→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : null;
 38→};
 39→
 40→const resolveCount = (
 41→  aggregate: Array<{count?: number}> | undefined,
 42→  fallback?: number,
 43→): number => {
 44→  return toCount(aggregate?.[0]?.count) ?? toCount(fallback) ?? 0;
 45→};
 46→
 47→const formatRelativeDate = (value: string | undefined): string => {
 48→  if (!value) return '';
 49→  const date = new Date(value);
 50→  if (Number.isNaN(date.getTime())) return value;
 51→  const now = Date.now();
 52→  const diff = now - date.getTime();
 53→  const mins = Math.floor(diff / 60000);
 54→  if (mins < 1) return 'Just now';
 55→  if (mins < 60) return `${mins}m ago`;
 56→  const hours = Math.floor(mins / 60);
 57→  if (hours < 24) return `${hours}h ago`;
 58→  const days = Math.floor(hours / 24);
 59→  if (days < 7) return `${days}d ago`;
 60→  return date.toLocaleDateString(undefined, {month: 'short', day: 'numeric', year: 'numeric'});
 61→};
 62→
 63→const extractBannerImage = (content: string | null | undefined): string | null => {
 64→  if (!content) return null;
 65→  try {
 66→    const parsed = JSON.parse(content);
 67→    const findImage = (node: any): string | null => {
 68→      if (node.type === 'image' && node.src) return node.src;
 69→      if (node.children) {
 70→        for (const child of node.children) {
 71→          const found = findImage(child);
 72→          if (found) return found;
 73→        }
 74→      }
 75→      return null;
 76→    };
 77→    return findImage(parsed.root ?? parsed);
 78→  } catch {
 79→    return null;
 80→  }
 81→};
 82→
 83→type CommentThreadProps = {
 84→  comment: JournalComment;
 85→  postId: string;
 86→  isLoggedIn: boolean;
 87→  isExpanded: boolean;
 88→  onReply: (commentId: string, userName: string) => void;
 89→  onToggleReplies: (commentId: string) => void;
 90→  colors: Palette;
 91→};
 92→
 93→function CommentThread({
 94→  comment,
 95→  postId,
 96→  isLoggedIn,
 97→  isExpanded,
 98→  onReply,
 99→  onToggleReplies,
100→  colors,
101→}: CommentThreadProps) {
102→  const repliesQuery = useQuery({
103→    queryKey: ['comment-replies', comment.id],
104→    queryFn: () => socialApi.getReplies(postId, comment.id),
105→    enabled: isExpanded,
106→  });
107→
108→  const replies = repliesQuery.data?.comments ?? [];
109→  const replyCount = comment.reply_count ?? 0;
110→  const userName = comment.users?.name || 'User';
111→
112→  return (
113→    <View>
114→      <View style={[styles.commentCard, {borderTopColor: colors.borderCard}]}>
115→        <View style={styles.commentHeader}>
116→          <Avatar
117→            uri={(comment.users as any)?.image_url}
118→            name={comment.users?.name}
119→            size={28}
120→          />
121→          <View style={styles.commentMeta}>
122→            <Text style={[styles.commentAuthor, {color: colors.textPrimary}]}>
123→              {userName}
124→            </Text>
125→            <Text style={[styles.commentTime, {color: colors.textFaint}]}>
126→              {formatRelativeDate(comment.created_at)}
127→            </Text>
128→          </View>
129→        </View>
130→        <Text style={[styles.commentBody, {color: colors.textSecondary}]}>
131→          {comment.comment || ''}
132→        </Text>
133→        <View style={styles.commentActions}>
134→          {isLoggedIn && (
135→            <Pressable
136→              style={styles.actionButton}
137→              onPress={() => onReply(comment.id, userName)}>
138→              <ReplyIcon size={14} color={colors.textMuted} />
139→              <Text style={[styles.actionText, {color: colors.textMuted}]}>
140→                Reply
141→              </Text>
142→            </Pressable>
143→          )}
144→          {replyCount > 0 && (
145→            <Pressable
146→              style={styles.actionButton}
147→              onPress={() => onToggleReplies(comment.id)}>
148→              <Text style={[styles.actionText, {color: colors.accentGold}]}>
149→                {isExpanded ? 'Hide replies' : `Show ${replyCount} ${replyCount === 1 ? 'reply' : 'replies'}`}
150→              </Text>
151→            </Pressable>
152→          )}
153→        </View>
154→      </View>
155→
156→      {isExpanded && (
157→        <View style={[styles.repliesContainer, {borderLeftColor: colors.borderLight}]}>
158→          {repliesQuery.isLoading ? (
159→            <View style={styles.repliesLoading}>
160→              <ActivityIndicator size="small" color={colors.loaderColor} />
161→            </View>
162→          ) : repliesQuery.isError ? (
163→            <Text style={[styles.repliesError, {color: colors.danger}]}>
164→              Failed to load replies.
165→            </Text>
166→          ) : (
167→            replies.map(reply => (
168→              <View key={reply.id} style={styles.replyCard}>
169→                <View style={styles.commentHeader}>
170→                  <Avatar
171→                    uri={(reply.users as any)?.image_url}
172→                    name={reply.users?.name}
173→                    size={24}
174→                  />
175→                  <View style={styles.commentMeta}>
176→                    <Text style={[styles.commentAuthor, {color: colors.textPrimary}]}>
177→                      {reply.users?.name || 'User'}
178→                    </Text>
179→                    <Text style={[styles.commentTime, {color: colors.textFaint}]}>
180→                      {formatRelativeDate(reply.created_at)}
181→                    </Text>
182→                  </View>
183→                </View>
184→                <Text style={[styles.replyBody, {color: colors.textSecondary}]}>
185→                  {reply.comment || ''}
186→                </Text>
187→              </View>
188→            ))
189→          )}
190→        </View>
191→      )}
192→    </View>
193→  );
194→}
