196→export function PostDetailScreen({route}: Props) {
197→  const {user, session} = useAuth();
198→  const {colors} = useTheme();
199→  const {journalId} = route.params;
200→  const token = session?.access_token ?? '';
201→  const [commentInput, setCommentInput] = useState('');
202→  const [repostCaption, setRepostCaption] = useState('');
203→  const [showRepost, setShowRepost] = useState(false);
204→  const [replyingTo, setReplyingTo] = useState<{id: string; userName: string} | null>(null);
205→  const [expandedReplies, setExpandedReplies] = useState<Set<string>>(new Set());
206→  const scrollViewRef = useRef<ScrollView>(null);
207→  const inputRef = useRef<TextInput>(null);
208→
209→  const handleReply = useCallback((commentId: string, userName: string) => {
210→    setReplyingTo({id: commentId, userName});
211→    setTimeout(() => {
212→      inputRef.current?.focus();
213→      scrollViewRef.current?.scrollToEnd({animated: true});
214→    }, 100);
215→  }, []);
216→
217→  const handleToggleReplies = useCallback((commentId: string) => {
218→    setExpandedReplies(prev => {
219→      const next = new Set(prev);
220→      if (next.has(commentId)) {
221→        next.delete(commentId);
222→      } else {
223→        next.add(commentId);
224→      }
225→      return next;
226→    });
227→  }, []);
228→
229→  const detailQuery = useQuery({
230→    queryKey: ['journal', journalId, user?.id],
231→    queryFn: () => mobileApi.getJournalById(journalId, user?.id),
232→  });
233→
234→  const commentsQuery = useQuery({
235→    queryKey: ['journal-comments', journalId],
236→    queryFn: () => socialApi.getComments(journalId, null, 20),
237→  });
238→
239→  const reactionMutation = useMutation({
240→    mutationFn: async (reactionType: string) => {
241→      const journal = detailQuery.data?.journal;
242→      const receiverId = journal?.user_id ?? journal?.users?.id;
243→      if (!token) throw new Error('Please log in to react.');
244→      if (!journal?.id || !receiverId) throw new Error('Missing journal data.');
245→      return socialApi.toggleReaction(token, {
246→        journalId: journal.id,
247→        receiverId,
248→        reactionType,
249→      });
250→    },
251→    onSuccess: () => {
252→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
253→      queryClient.invalidateQueries({queryKey: ['feed']});
254→    },
255→    onError: e => Alert.alert('Reaction failed', e instanceof Error ? e.message : 'Error'),
256→  });
257→
258→  const bookmarkMutation = useMutation({
259→    mutationFn: async () => {
260→      if (!token) throw new Error('Please log in to bookmark.');
261→      return socialApi.toggleBookmark(token, {journalId});
262→    },
263→    onSuccess: () => {
264→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
265→      queryClient.invalidateQueries({queryKey: ['feed']});
266→    },
267→    onError: e => Alert.alert('Bookmark failed', e instanceof Error ? e.message : 'Error'),
268→  });
269→
270→  const addCommentMutation = useMutation({
271→    mutationFn: async () => {
272→      const body = commentInput.trim();
273→      const receiverId = detailQuery.data?.journal?.user_id ?? detailQuery.data?.journal?.users?.id;
274→      if (!token) throw new Error('Please log in to comment.');
275→      if (!body) throw new Error('Comment cannot be empty.');
276→      if (!receiverId) throw new Error('Missing journal owner.');
277→      return socialApi.addComment(token, {
278→        comments: body,
279→        postId: journalId,
280→        receiverId,
281→        parentId: replyingTo?.id,
282→      });
283→    },
284→    onSuccess: () => {
285→      const parentId = replyingTo?.id;
286→      setCommentInput('');
287→      setReplyingTo(null);
288→      queryClient.invalidateQueries({queryKey: ['journal-comments', journalId]});
289→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
290→      if (parentId) {
291→        queryClient.invalidateQueries({queryKey: ['comment-replies', parentId]});
292→      }
293→    },
294→    onError: e => Alert.alert('Comment failed', e instanceof Error ? e.message : 'Error'),
295→  });
296→
297→  const repostMutation = useMutation({
298→    mutationFn: async () => {
299→      if (!token) throw new Error('Please log in to repost.');
300→      return socialApi.createRepost(token, {
301→        sourceJournalId: journalId,
302→        caption: repostCaption.trim() || undefined,
303→      });
304→    },
305→    onSuccess: () => {
306→      setRepostCaption('');
307→      setShowRepost(false);
308→      Alert.alert('Reposted', 'Post was reposted to your feed.');
309→      queryClient.invalidateQueries({queryKey: ['feed']});
310→    },
311→    onError: e => Alert.alert('Repost failed', e instanceof Error ? e.message : 'Error'),
312→  });
313→
314→  const journal = detailQuery.data?.journal;
315→  const likeCount = resolveCount(journal?.like_count, journal?.likes_count);
316→  const commentCount = resolveCount(journal?.comment_count, journal?.comments_count);
317→  const bookmarkCount = resolveCount(journal?.bookmark_count);
318→  const comments = commentsQuery.data?.comments ?? [];
319→  const bannerImage = useMemo(() => extractBannerImage(journal?.content), [journal?.content]);
320→
321→  if (detailQuery.isLoading) {
322→    return (
323→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
324→        <View style={styles.loadingContainer}>
325→          <SkeletonLoader height={200} borderRadius={0} />
326→          <View style={styles.contentPadding}>
327→            <SkeletonLoader width="70%" height={24} />
328→            <SkeletonLoader width="40%" height={16} style={{marginTop: 12}} />
329→            <SkeletonLoader width="100%" height={16} style={{marginTop: 20}} />
330→            <SkeletonLoader width="100%" height={16} style={{marginTop: 8}} />
331→            <SkeletonLoader width="60%" height={16} style={{marginTop: 8}} />
332→          </View>
333→        </View>
334→      </SafeAreaView>
335→    );
336→  }
337→
338→  if (detailQuery.isError) {
339→    return (
340→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
341→        <View style={styles.contentPadding}>
342→          <Text style={[styles.errorText, {color: colors.danger}]}>
343→            Unable to load this post.
344→          </Text>
345→        </View>
346→      </SafeAreaView>
347→    );
348→  }
349→
350→  return (
351→    <ScrollView
352→      ref={scrollViewRef}
353→      style={[styles.scroll, {backgroundColor: colors.bgPrimary}]}
354→      showsVerticalScrollIndicator={false}>
355→      {/* Banner image */}
356→      {bannerImage && (
357→        <Image source={{uri: bannerImage}} style={styles.banner} resizeMode="cover" />
358→      )}
359→
360→      <View style={styles.contentPadding}>
361→        {/* Title */}
362→        <Text style={[styles.title, {color: colors.textHeading}]}>
363→          {journal?.title || 'Untitled Post'}
364→        </Text>
365→
366→        {/* Author section */}
367→        <View style={styles.authorRow}>
368→          <Avatar
369→            uri={journal?.users?.image_url}
370→            name={journal?.users?.name}
371→            size={36}
372→            badge={journal?.users?.badge as 'legend' | 'og' | undefined}
373→          />
374→          <View style={styles.authorInfo}>
375→            <View style={styles.authorNameRow}>
376→              <Text style={[styles.authorName, {color: colors.textPrimary}]}>
377→                {journal?.users?.name || 'Unknown author'}
378→              </Text>
379→              {journal?.users?.badge ? (
380→                <BadgeCheckIcon size={16} badge={journal.users.badge as 'legend' | 'og'} />
381→              ) : null}
382→            </View>
383→            <Text style={[styles.dateText, {color: colors.textMuted}]}>
384→              {formatRelativeDate(journal?.created_at)}
385→            </Text>
386→          </View>
387→        </View>
388→
389→        {/* Action bar */}
390→        <ActionBar
391→          likeCount={likeCount}
392→          commentCount={commentCount}
393→          bookmarkCount={bookmarkCount}
394→          isLiked={journal?.has_liked}
395→          isBookmarked={journal?.has_bookmarked}
396→          userReaction={journal?.user_reaction}
397→          onReact={type => reactionMutation.mutate(type)}
398→          onComment={() => {/* scroll to comments */}}
399→          onBookmark={() => bookmarkMutation.mutate()}
400→          onRepost={() => setShowRepost(!showRepost)}
401→        />
402→
403→        {/* Repost section */}
404→        {showRepost && (
405→          <View style={[styles.repostSection, {backgroundColor: colors.bgSecondary, borderColor: colors.borderLight}]}>
406→            <TextInput
407→              value={repostCaption}
408→              onChangeText={setRepostCaption}
409→              placeholder="Add an optional caption"
410→              placeholderTextColor={colors.textFaint}
411→              style={[styles.commentInput, {backgroundColor: colors.bgElevated, borderColor: colors.borderCard, color: colors.textPrimary}]}
412→              maxLength={280}
413→              multiline
414→            />
415→            <PrimaryButton
416→              label={repostMutation.isPending ? 'Reposting...' : 'Repost to feed'}
417→              onPress={() => repostMutation.mutate()}
418→              disabled={repostMutation.isPending}
419→            />
420→          </View>
421→        )}
422→
423→        {/* Divider */}
424→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
425→
426→        {/* Content body */}
427→        <LexicalRenderer content={journal?.content} />
428→
429→        {/* Related posts */}
430→        <RelatedPosts journalId={journalId} />
431→
432→        {/* Divider */}
433→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
434→
435→        {/* Comments section */}
436→        <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>
437→          Comments ({commentCount})
438→        </Text>
439→
440→        {commentsQuery.isLoading ? (
441→          <View style={styles.commentLoading}>
442→            <ActivityIndicator color={colors.loaderColor} />
443→          </View>
444→        ) : comments.filter(c => !c.parent_id).length === 0 ? (
445→          <Text style={[styles.noComments, {color: colors.textMuted}]}>
446→            No comments yet. Be the first!
447→          </Text>
448→        ) : (
449→          comments
450→            .filter(c => !c.parent_id)
451→            .map(comment => (
452→              <CommentThread
453→                key={comment.id}
454→                comment={comment}
455→                postId={journalId}
456→                isLoggedIn={!!token}
457→                isExpanded={expandedReplies.has(comment.id)}
458→                onReply={handleReply}
459→                onToggleReplies={handleToggleReplies}
460→                colors={colors}
461→              />
462→            ))
463→        )}
464→
465→        {/* Comment input */}
466→        {token ? (
467→          <View style={styles.commentInputRow}>
468→            {replyingTo && (
469→              <View style={[styles.replyBanner, {backgroundColor: colors.bgSecondary}]}>
470→                <Text style={[styles.replyBannerText, {color: colors.textPrimary}]}>
471→                  Replying to {replyingTo.userName}
472→                </Text>
473→                <Pressable onPress={() => setReplyingTo(null)} hitSlop={8}>
474→                  <XIcon size={16} color={colors.textMuted} />
475→                </Pressable>
476→              </View>
477→            )}
478→            <TextInput
479→              ref={inputRef}
480→              value={commentInput}
481→              onChangeText={setCommentInput}
482→              placeholder={replyingTo ? `Reply to ${replyingTo.userName}...` : 'Write a comment...'}
483→              placeholderTextColor={colors.textFaint}
484→              style={[
485→                styles.commentInput,
486→                {
487→                  backgroundColor: colors.bgSecondary,
488→                  borderColor: colors.borderCard,
489→                  color: colors.textPrimary,
490→                },
491→              ]}
492→              maxLength={200}
493→              multiline
494→            />
495→            <PrimaryButton
496→              label={addCommentMutation.isPending ? 'Posting...' : 'Post'}
497→              onPress={() => addCommentMutation.mutate()}
498→              disabled={commentInput.trim().length === 0 || addCommentMutation.isPending}
499→            />
500→          </View>
501→        ) : null}
502→
503→        <View style={styles.bottomSpacer} />
504→      </View>
505→    </ScrollView>
506→  );
507→}
