 35→const toCount = (value: unknown): number | null => {
 36→  const parsed = Number(value);
 37→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : null;
 38→};
 39→
 40→const resolveCount = (
 41→  aggregate: Array<{count?: number}> | undefined,
 42→  fallback?: number,
 43→): number => {
 44→  return toCount(aggregate?.[0]?.count) ?? toCount(fallback) ?? 0;
 45→};
 46→
 47→const formatRelativeDate = (value: string | undefined): string => {
 48→  if (!value) return '';
 49→  const date = new Date(value);
 50→  if (Number.isNaN(date.getTime())) return value;
 51→  const now = Date.now();
 52→  const diff = now - date.getTime();
 53→  const mins = Math.floor(diff / 60000);
 54→  if (mins < 1) return 'Just now';
 55→  if (mins < 60) return `${mins}m ago`;
 56→  const hours = Math.floor(mins / 60);
 57→  if (hours < 24) return `${hours}h ago`;
 58→  const days = Math.floor(hours / 24);
 59→  if (days < 7) return `${days}d ago`;
 60→  return date.toLocaleDateString(undefined, {month: 'short', day: 'numeric', year: 'numeric'});
 61→};
 62→
 63→const extractBannerImage = (content: string | null | undefined): string | null => {
 64→  if (!content) return null;
 65→  try {
 66→    const parsed = JSON.parse(content);
 67→    const findImage = (node: any): string | null => {
 68→      if (node.type === 'image' && node.src) return node.src;
 69→      if (node.children) {
 70→        for (const child of node.children) {
 71→          const found = findImage(child);
 72→          if (found) return found;
 73→        }
 74→      }
 75→      return null;
 76→    };
 77→    return findImage(parsed.root ?? parsed);
 78→  } catch {
 79→    return null;
 80→  }
 81→};
