138→          {comment.comment || ''}
139→        </Text>
140→        <View style={[styles.commentActions, {paddingLeft: bodyPaddingLeft}]}>
141→          {isLoggedIn && (
142→            <Pressable
143→              style={styles.actionButton}
144→              onPress={() => onReply(comment.id, userName)}>
145→              <ReplyIcon size={14} color={colors.textMuted} />
146→              <Text style={[styles.actionText, {color: colors.textMuted}]}>
147→                Reply
148→              </Text>
149→            </Pressable>
150→          )}
151→          {replyCount > 0 && (
152→            <Pressable
153→              style={styles.actionButton}
154→              onPress={() => onToggleReplies(comment.id)}>
155→              <Text style={[styles.actionText, {color: colors.accentGold}]}>
156→                {isExpanded ? 'Hide replies' : `Show ${replyCount} ${replyCount === 1 ? 'reply' : 'replies'}`}
157→              </Text>
158→            </Pressable>
159→          )}
160→        </View>
161→      </View>
162→
163→      {isExpanded && (
164→        <View style={[styles.repliesContainer, {borderLeftColor: colors.borderLight, marginLeft: repliesMarginLeft}]}>
165→          {repliesQuery.isLoading ? (
166→            <View style={styles.repliesLoading}>
