  1→import { MOBILE_ENV } from '../../config/env';
  2→
  3→const DEFAULT_TIMEOUT_MS = 15000;
  4→const DEFAULT_RETRIES = 2;
  5→const RETRY_BASE_DELAY_MS = 250;
  6→const RETRY_MAX_DELAY_MS = 2500;
  7→const MAX_SERVER_RETRY_AFTER_MS = 30000;
  8→const RETRIABLE_METHODS = new Set(['GET', 'HEAD', 'OPTIONS']);
  9→const JSON_CONTENT_TYPE_PATTERN = /application\/json|\/[a-z0-9.+-]+\+json/i;
 10→
 11→export class ApiError extends Error {
 12→  readonly status: number;
 13→  readonly body?: unknown;
 14→
 15→  constructor(message: string, status: number, body?: unknown) {
 16→    super(message);
 17→    this.name = 'ApiError';
 18→    this.status = status;
 19→    this.body = body;
 20→  }
 21→}
 22→
 23→export class ApiTimeoutError extends ApiError {
 24→  readonly timeoutMs: number;
 25→
 26→  constructor(timeoutMs: number, body?: unknown) {
 27→    super(`Request timed out after ${timeoutMs}ms`, 0, body);
 28→    this.name = 'ApiTimeoutError';
 29→    this.timeoutMs = timeoutMs;
 30→  }
 31→}
 32→
 33→export class ApiNetworkError extends ApiError {
 34→  readonly originalError?: unknown;
 35→
 36→  constructor(message: string, originalError?: unknown) {
 37→    super(message, 0);
 38→    this.name = 'ApiNetworkError';
 39→    this.originalError = originalError;
 40→  }
 41→}
 42→
 43→export type ApiRequestInit = RequestInit & {
 44→  timeoutMs?: number;
 45→  retries?: number;
 46→};
 47→
 48→const wait = async (ms: number): Promise<void> => {
 49→  await new Promise((resolve) => {
 50→    setTimeout(() => resolve(undefined), ms);
 51→  });
 52→};
 53→
 54→const shouldRetryStatus = (status: number): boolean => {
 55→  return status === 408 || status === 429 || status >= 500;
 56→};
 57→
 58→const shouldRetryMethod = (method: string): boolean => RETRIABLE_METHODS.has(method.toUpperCase());
 59→
 60→const parseRetryAfterMs = (value: string | null): number | null => {
 61→  if (!value) {
 62→    return null;
 63→  }
 64→
 65→  const numericValue = Number(value);
 66→  if (Number.isFinite(numericValue) && numericValue >= 0) {
 67→    return Math.min(numericValue * 1000, MAX_SERVER_RETRY_AFTER_MS);
 68→  }
 69→
 70→  const dateMs = Date.parse(value);
 71→  if (Number.isNaN(dateMs)) {
 72→    return null;
 73→  }
 74→
 75→  return Math.min(Math.max(dateMs - Date.now(), 0), MAX_SERVER_RETRY_AFTER_MS);
 76→};
 77→
 78→const backoffDelay = (attempt: number, retryAfterMs?: number | null): number => {
 79→  if (retryAfterMs && retryAfterMs > 0) {
 80→    return retryAfterMs;
 81→  }
 82→
 83→  const jitter = Math.floor(Math.random() * 120);
 84→  return Math.min(RETRY_BASE_DELAY_MS * 2 ** attempt + jitter, RETRY_MAX_DELAY_MS);
 85→};
 86→
 87→const buildUrl = (path: string): string => {
 88→  const trimmedPath = path.trim();
 89→  if (/^https?:\/\//i.test(trimmedPath)) {
 90→    return trimmedPath;
 91→  }
 92→
 93→  const normalizedPath = trimmedPath.startsWith('/') ? trimmedPath : `/${trimmedPath}`;
 94→  return `${MOBILE_ENV.API_BASE_URL}${normalizedPath}`;
 95→};
 96→
 97→const parseBody = async (response: Response): Promise<unknown> => {
 98→  if (response.status === 204 || response.status === 205) {
 99→    return undefined;
100→  }
101→
102→  const contentType = response.headers.get('content-type') ?? '';
103→  if (JSON_CONTENT_TYPE_PATTERN.test(contentType)) {
104→    return response.json().catch(() => undefined);
105→  }
106→
107→  return response.text().catch(() => undefined);
108→};
109→
110→const extractErrorMessage = (status: number, statusText: string, body: unknown): string => {
111→  if (typeof body === 'string' && body.trim().length > 0) {
112→    return body.trim();
113→  }
114→
115→  if (typeof body === 'object' && body) {
116→    const payload = body as { error?: unknown; message?: unknown; detail?: unknown };
117→    const candidate = payload.error ?? payload.message ?? payload.detail;
118→    if (typeof candidate === 'string' && candidate.trim().length > 0) {
119→      return candidate.trim();
120→    }
121→  }
122→
123→  const suffix = statusText.trim();
124→  return suffix ? `Request failed (${status} ${suffix})` : `Request failed (${status})`;
125→};
126→
127→const shouldRetryError = (error: unknown): boolean => {
128→  return (
129→    error instanceof ApiTimeoutError ||
130→    error instanceof ApiNetworkError ||
131→    error instanceof TypeError
132→  );
133→};
134→
135→const normalizeError = (
136→  error: unknown,
137→  timeoutMs: number,
138→  didTimeout: boolean,
139→  callerSignal: AbortSignal | undefined,
140→): unknown => {
141→  if (!(error instanceof Error)) {
142→    return new Error('Unknown request error');
143→  }
144→
145→  if (error.name === 'AbortError') {
146→    if (didTimeout) {
147→      return new ApiTimeoutError(timeoutMs);
148→    }
149→
150→    if (callerSignal?.aborted) {
151→      return error;
152→    }
153→  }
154→
155→  if (error instanceof TypeError) {
156→    return new ApiNetworkError('Network request failed', error);
157→  }
158→
159→  return error;
160→};
161→
162→export async function apiRequest<T>(path: string, init: ApiRequestInit = {}): Promise<T> {
163→  const method = (init.method ?? 'GET').toUpperCase();
164→  const timeoutMs = init.timeoutMs ?? DEFAULT_TIMEOUT_MS;
165→  const retries = Math.max(0, Math.floor(init.retries ?? DEFAULT_RETRIES));
166→  const callerSignal = init.signal;
167→  const requestInit: RequestInit = { ...init };
168→  delete (requestInit as ApiRequestInit).timeoutMs;
169→  delete (requestInit as ApiRequestInit).retries;
170→  requestInit.method = method;
171→
172→  const headers = new Headers(requestInit.headers ?? {});
173→  if (!headers.has('Accept')) {
174→    headers.set('Accept', 'application/json');
175→  }
176→  requestInit.headers = headers;
177→
178→  const maxAttempts = shouldRetryMethod(method) ? retries + 1 : 1;
179→
180→  for (let attempt = 0; attempt < maxAttempts; attempt += 1) {
181→    const controller = new AbortController();
182→    let timeoutId: ReturnType<typeof setTimeout> | null = null;
183→    let didTimeout = false;
184→    let callerAbortListener: (() => void) | null = null;
185→
186→    if (callerSignal) {
187→      if (callerSignal.aborted) {
188→        controller.abort();
189→      } else {
190→        callerAbortListener = () => controller.abort();
191→        callerSignal.addEventListener('abort', callerAbortListener, { once: true });
192→      }
193→    }
194→
195→    if (timeoutMs > 0) {
196→      timeoutId = setTimeout(() => {
197→        didTimeout = true;
198→        controller.abort();
199→      }, timeoutMs);
200→    }
201→
202→    try {
203→      const response = await fetch(buildUrl(path), {
204→        ...requestInit,
205→        signal: controller.signal,
206→      });
207→
208→      const body = await parseBody(response);
209→
210→      if (!response.ok) {
211→        if (attempt < maxAttempts - 1 && shouldRetryStatus(response.status)) {
212→          const retryAfterMs = parseRetryAfterMs(response.headers.get('retry-after'));
213→          await wait(backoffDelay(attempt, retryAfterMs));
214→          continue;
215→        }
216→
