133→export const MOBILE_ENV: MobileEnv = resolvedMobileEnv.env;
134→export const IS_SUPABASE_CONFIGURED = resolvedMobileEnv.isSupabaseConfigured;
135→export const ENV_WARNINGS = Object.freeze([...resolvedMobileEnv.warnings]);
