  6→const RETRY_MAX_DELAY_MS = 2500;
  7→const MAX_SERVER_RETRY_AFTER_MS = 30000;
  8→const RETRIABLE_METHODS = new Set(['GET', 'HEAD', 'OPTIONS']);
  9→const JSON_CONTENT_TYPE_PATTERN = /application\/json|\/[a-z0-9.+-]+\+json/i;
