 11→export class ApiError extends Error {
 12→  readonly status: number;
 13→  readonly body?: unknown;
 14→
 15→  constructor(message: string, status: number, body?: unknown) {
 16→    super(message);
 17→    this.name = 'ApiError';
 18→    this.status = status;
 19→    this.body = body;
 20→  }
 21→}
 22→
 23→export class ApiTimeoutError extends ApiError {
 24→  readonly timeoutMs: number;
 25→
 26→  constructor(timeoutMs: number, body?: unknown) {
 27→    super(`Request timed out after ${timeoutMs}ms`, 0, body);
 28→    this.name = 'ApiTimeoutError';
 29→    this.timeoutMs = timeoutMs;
 30→  }
 31→}
 32→
 33→export class ApiNetworkError extends ApiError {
 34→  readonly originalError?: unknown;
 35→
 36→  constructor(message: string, originalError?: unknown) {
 37→    super(message, 0);
 38→    this.name = 'ApiNetworkError';
 39→    this.originalError = originalError;
 40→  }
 41→}
