 43→export type ApiRequestInit = RequestInit & {
 44→  timeoutMs?: number;
 45→  retries?: number;
 46→};
 47→
 48→const wait = async (ms: number): Promise<void> => {
 49→  await new Promise((resolve) => {
 50→    setTimeout(() => resolve(undefined), ms);
 51→  });
 52→};
 53→
 54→const shouldRetryStatus = (status: number): boolean => {
 55→  return status === 408 || status === 429 || status >= 500;
 56→};
 57→
 58→const shouldRetryMethod = (method: string): boolean => RETRIABLE_METHODS.has(method.toUpperCase());
 59→
 60→const parseRetryAfterMs = (value: string | null): number | null => {
 61→  if (!value) {
 62→    return null;
 63→  }
 64→
 65→  const numericValue = Number(value);
 66→  if (Number.isFinite(numericValue) && numericValue >= 0) {
 67→    return Math.min(numericValue * 1000, MAX_SERVER_RETRY_AFTER_MS);
 68→  }
 69→
 70→  const dateMs = Date.parse(value);
 71→  if (Number.isNaN(dateMs)) {
 72→    return null;
 73→  }
 74→
 75→  return Math.min(Math.max(dateMs - Date.now(), 0), MAX_SERVER_RETRY_AFTER_MS);
 76→};
 77→
 78→const backoffDelay = (attempt: number, retryAfterMs?: number | null): number => {
 79→  if (retryAfterMs && retryAfterMs > 0) {
 80→    return retryAfterMs;
 81→  }
 82→
 83→  const jitter = Math.floor(Math.random() * 120);
 84→  return Math.min(RETRY_BASE_DELAY_MS * 2 ** attempt + jitter, RETRY_MAX_DELAY_MS);
 85→};
